export async function handleIntel(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;

  try {
    await ensureProfilesLoaded();
  } catch (err) {
    await ctx.reply(`Daily Intel 設定載入失敗：${(err as Error).message}`);
    return;
  }

  const raw = (typeof ctx.match === "string" ? ctx.match : "").trim();
  const [sub = "", ...args] = raw.split(/\s+/);

  if (sub === "topic") {
    await handleTopic(ctx, raw);
    return;
  }

  if (sub === "podcast") {
    await handlePodcast(ctx, args);
    return;
  }

  if (!sub || sub === "profiles") {
    await ctx.reply(formatProfileList(profileStore.list()));
    return;
  }

  if (sub === "show") {
    const profile = findProfile(args[0]);
    if (!profile) {
      await ctx.reply(profileNotFound(args[0]));
      return;
    }
    await ctx.reply(formatProfile(profile));
    return;
  }

  if (sub === "profile") {
    const [profileId, action] = args;
    if (!profileId || !["enable", "disable"].includes(action) || args.length !== 2) {
      await ctx.reply("用法：/intel profile <profile-id> <enable|disable>");
      return;
    }
    const profile = await profileStore.setEnabled(profileId, action === "enable");
    if (!profile) {
      await ctx.reply(profileNotFound(profileId));
      return;
    }
    await ctx.reply(`Profile "${profile.id}" 已${profile.enabled ? "啟用" : "停用"}。`);
    return;
  }

  if (sub === "sources") {
    const profile = findProfile(args[0]);
    if (!profile) {
      await ctx.reply(profileNotFound(args[0]));
      return;
    }
    await ctx.reply(formatSources(profile, sourceCatalog.match(profile)));
    return;
  }

  if (sub === "source") {
    const [sourceId, action] = args;
    if (!sourceId || !["enable", "disable"].includes(action) || args.length !== 2) {
      await ctx.reply("用法：/intel source <source-id> <enable|disable>");
      return;
    }
    const source = await sourceCatalog.setEnabled(sourceId, action === "enable");
    if (!source) {
      const available = sourceCatalog.list().map((entry) => entry.id).join(", ");
      await ctx.reply(`找不到 Source "${sourceId}"。可用：${available || "(無)"}`);
      return;
    }
    await ctx.reply(`Source "${source.id}" 已${source.enabled ? "啟用" : "停用"}。`);
    return;
  }

  if (sub === "run") {
    const profile = findProfile(args[0]);
    if (!profile) {
      await ctx.reply(profileNotFound(args[0]));
      return;
    }
    if (!profile.enabled) {
      await ctx.reply(`Profile "${profile.id}" 目前停用。`);
      return;
    }
    const sources = sourceCatalog.match(profile);
    await ctx.reply(
      `Daily Intel 已開始執行 ${profile.id}。\n` +
        `符合來源: ${sources.length}\n` +
        "完成後會回報 run id 與摘要；期間可稍後用 /intel status <run-id> 查詢。",
    );
    const run = await getService().runProfile(
      profile,
      sources,
      ctx.from?.id,
      (artifact) => sendReportArtifact(ctx, profile.name, artifact),
    );
    enqueuePodcastForRun(ctx, run);
    await ctx.reply(
      `Daily Intel run ${run.id}\n` +
        `Profile: ${profile.id}\n` +
        `狀態: ${run.status}\n` +
        `符合來源: ${sources.length}\n` +
        `新增項目: ${String(run.metrics.itemsInserted ?? 0)}\n` +
        `重複項目: ${String(run.metrics.duplicates ?? 0)}\n` +
        `日期排除: ${String(run.metrics.dateFilteredItems ?? 0)}\n` +
        `失敗來源: ${String(run.metrics.failedSources ?? 0)}\n` +
        `完成分析: ${String(run.metrics.analyzedItems ?? 0)}\n` +
        `報告項目: ${String(run.metrics.reportItems ?? 0)}\n` +
        `Delivery: ${run.stages.find((stage) => stage.stage === "deliver")?.status ?? "unknown"}`,
    );
    await sendLearningDraftPrompt(ctx, profile, run);
    return;
  }

  if (sub === "status") {
    const id = args[0];
    if (!id) {
      await ctx.reply("用法：/intel status <run-id>");
      return;
    }
    const run = getService().getRun(id);
    if (!run) {
      await ctx.reply(`找不到 Daily Intel run ${id}。`);
      return;
    }
    await ctx.reply(formatRun(run));
    return;
  }

  if (sub === "report") {
    await handleReport(ctx, args);
    return;
  }

  if (sub === "retry") {
    await handleRetry(ctx, args);
    return;
  }

  if (sub === "retry-source") {
    await handleSourceRetry(ctx, args);
    return;
  }

  if (sub === "search") {
    const query = args.join(" ").trim();
    if (query.length < 2 || query.length > 100) {
      await ctx.reply("用法：/intel search <2-100 字關鍵字>");
      return;
    }
    const results = getService().searchHistory(query, 10);
    if (results.length === 0) {
      await ctx.reply(`找不到包含 "${query}" 的歷史情報或分析。`);
      return;
    }
    const lines = results.map((result, index) => {
      const analysis = result.summary
        ? `\n分析${result.profileId ? ` [${result.profileId}]` : ""}: ${result.summary}`
        : "";
      return `${index + 1}. [${result.sourceId}] ${result.title}${analysis}\n${result.canonicalUrl}`;
    });
    await ctx.reply(`Daily Intel 搜尋 "${query}"（${results.length}）：\n\n${lines.join("\n\n")}`);
    return;
  }

  if (sub === "clusters") {
    const runId = args[0];
    if (!runId || args.length !== 1) {
      await ctx.reply("用法：/intel clusters <run-id>");
      return;
    }
    if (!getService().getRun(runId)) {
      await ctx.reply(`找不到 Daily Intel run ${runId}。`);
      return;
    }
    const clusters = getService().listEventClusters(runId);
    if (clusters.length === 0) {
      await ctx.reply(`Run ${runId} 沒有 event cluster。`);
      return;
    }
    const lines = clusters.map((cluster) =>
      `${cluster.id} primary=${cluster.primaryItemId}\n` +
      `${cluster.canonicalTitle}\nitems: ${cluster.itemIds.join(", ")}`
    );
    await ctx.reply(`Run ${runId} event clusters（${clusters.length}）：\n\n${lines.join("\n\n")}`);
    return;
  }

  if (sub === "cluster") {
    await handleClusterMutation(ctx, args);
    return;
  }

  if (sub === "weekly") {
    const [profileId, requestedDate] = args;
    const profile = findProfile(profileId);
    if (!profile) {
      await ctx.reply(profileNotFound(profileId));
      return;
    }
    if (args.length > 2 || (requestedDate && !/^\d{4}-\d{2}-\d{2}$/.test(requestedDate))) {
      await ctx.reply("用法：/intel weekly <profile-id> [YYYY-MM-DD]");
      return;
    }
    const endDate = requestedDate ?? new Date().toISOString().slice(0, 10);
    const trend = getService().getWeeklyTrend(profile.id, endDate);
    const categories = trend.topCategories.map((entry) => `${entry.name}(${entry.count})`).join(", ");
    const sources = trend.topSources.map((entry) => `${entry.name}(${entry.count})`).join(", ");
    const highlights = trend.highlights.length > 0
      ? trend.highlights.map((entry, index) =>
          `${index + 1}. ${entry.title} [${entry.sourceId}] score=${entry.score.toFixed(3)}\n` +
          `${entry.summary}\n${entry.canonicalUrl}`
        ).join("\n\n")
      : "此期間沒有完成分析的情報。";
    await ctx.reply(
      `${profile.name} 每週趨勢\n` +
      `${trend.startDate} ~ ${trend.endDate}\n` +
      `情報數：${trend.totalItems}\n` +
      `平均評分：${trend.averageScore.toFixed(3)}\n` +
      `主要分類：${categories || "無"}\n` +
      `主要來源：${sources || "無"}\n\n` +
      highlights,
    );
    return;
  }

  if (sub === "schedule") {
    await scheduleProfile(ctx, args);
    return;
  }

  if (sub === "candidates") {
    const profile = args[0] ? findProfile(args[0]) : undefined;
    if (args[0] && !profile) {
      await ctx.reply(profileNotFound(args[0]));
      return;
    }
    const candidates = getService().listExplorationCandidates(profile?.id);
    if (candidates.length === 0) {
      await ctx.reply(`目前沒有${profile ? ` Profile "${profile.id}" 的` : ""}探索候選來源。`);
      return;
    }
    const lines = candidates.slice(0, 20).map((candidate) =>
      `#${candidate.id} [${candidate.status}/${candidate.successfulRuns}] ` +
      `${candidate.domain}\n${candidate.title}\n${candidate.url}`
    );
    await ctx.reply(`探索候選來源（${candidates.length}）：\n${lines.join("\n\n")}`);
    return;
  }

  if (sub === "learn") {
    await handleLearn(ctx, args);
    return;
  }

  if (sub === "candidate") {
    const id = Number(args[0]);
    const action = args[1];
    if (!Number.isInteger(id) || id <= 0 || !["propose", "approve", "reject"].includes(action)) {
      await ctx.reply("用法：/intel candidate <id> <propose|approve|reject>");
      return;
    }
    const status = action === "propose" ? "proposed" : action === "approve" ? "approved" : "rejected";
    const candidate = getService().updateExplorationCandidateStatus(id, status);
    if (!candidate) {
      await ctx.reply(`找不到探索候選來源 #${id}。`);
      return;
    }
    await ctx.reply(
      `探索候選來源 #${candidate.id} 已標記為 ${candidate.status}。\n` +
      `${candidate.domain}\n${candidate.url}`,
    );
    return;
  }

  await ctx.reply(
    "用法：\n" +
      "/intel profiles\n" +
      "/intel show <profile-id>\n" +
      "/intel profile <profile-id> <enable|disable>\n" +
      "/intel topic add <name> --keywords <keyword1,keyword2,...>\n" +
      "/intel topic source <profile-id> <add|remove> <source-id>\n" +
      "/intel topic remove <profile-id>\n" +
      "/intel sources <profile-id>\n" +
      "/intel source <source-id> <enable|disable>\n" +
      "/intel run <profile-id>\n" +
      "/intel status <run-id>\n" +
      "/intel report <profile-id> [YYYY-MM-DD]\n" +
      "/intel retry <run-id>\n" +
      "/intel retry-source <run-id> [source-id]\n" +
      "/intel search <query>\n" +
      "/intel clusters <run-id>\n" +
      "/intel cluster merge <run-id> <cluster-a> <cluster-b> [primary-item-id]\n" +
      "/intel cluster split <run-id> <cluster-id> <item-id>\n" +
      "/intel weekly <profile-id> [YYYY-MM-DD]\n" +
      "/intel learn <profile-id> [run-id]\n" +
      "/intel candidates [profile-id]\n" +
      "/intel candidate <id> <propose|approve|reject>\n" +
      "/intel podcast <status|retry> [job-id]\n" +
      "/intel schedule <profile-id> daily <HH:MM>",
  );
}

