  private profiles = new Map<string, IntelProfile>();

  constructor(private readonly filePath: string) {}

  async load(): Promise<ReadonlyArray<IntelProfile>> {
    const raw = await readFile(this.filePath, "utf8");
    let parsed: unknown;
    try {
      parsed = JSON.parse(raw);
    } catch (err) {
      throw new Error(
        `Intel profile config is invalid JSON (${this.filePath}): ${(err as Error).message}`,
      );
    }
    const config = validateProfilesConfig(parsed);
    this.profiles = new Map(config.profiles.map((profile) => [profile.id, profile]));
    return this.list();
  }

  list(): ReadonlyArray<IntelProfile> {
    return Array.from(this.profiles.values()).sort((a, b) => a.id.localeCompare(b.id));
  }

  get(id: string): IntelProfile | undefined {
    return this.profiles.get(id);
  }

